package uk.ac.ed.ltg.jdm.scoring;import java.util.ArrayList;import java.util.List;/** * The Class MyScore. */public class Score {	public static Score newSeparator(final String group) {		final Score score = new Score(0, 0, 0, group);		score.setSeparator(true);		return score;	}	private double truePositives = 0;	private double falsePositives = 0;	private double falseNegatives = 0;	private String group;	private boolean isSeparator = false;	private List<Result> truePositiveResults = new ArrayList<Result>();	private List<Result> falsePositiveResults = new ArrayList<Result>();	private List<Result> falseNegativeResults = new ArrayList<Result>();	/**	 * The Constructor.	 */	public Score() {	}	public Score(final int truePositives, final double falsePositives,			final double falseNegatives) {		this(truePositives, falsePositives, falseNegatives, null);	}	public Score(final int truePositives, final double falsePositives,			final double falseNegatives, final String group) {		this.truePositives = truePositives;		this.falsePositives = falsePositives;		this.falseNegatives = falseNegatives;		this.group = group;	}	public void add(final Score score) {		this.truePositives += score.truePositives;		this.falsePositives += score.falsePositives;		this.falseNegatives += score.falseNegatives;		this.truePositiveResults.addAll(score.getTruePositiveResults());		this.falsePositiveResults.addAll(score.getFalsePositiveResults());		this.falseNegativeResults.addAll(score.getFalseNegativeResults());	}	public void addFalseNegativeResult(final Result result) {		this.falseNegativeResults.add(result);	}	public void addFalsePositiveResult(final Result result) {		this.falsePositiveResults.add(result);	}	public void addTruePositiveResult(final Result result) {		this.truePositiveResults.add(result);	}	/**	 * F1.	 * 	 * @return the float	 */	public float f1() {		final float alpha = 0.5f;		if (precision() == 0f || recall() == 0f)			return 0f;		else			return (1 / (alpha / precision() + (1 - alpha) / recall()));	}	/**	 * F-measure.	 * 	 * @return the float	 */	public float fmeasure(final float alpha) {		if (precision() == 0f || recall() == 0f)			return 0f;		else			return (1 / (alpha / precision() + (1 - alpha) / recall()));	}	/**	 * @return the falseNegativeResults	 */	public List<Result> getFalseNegativeResults() {		return falseNegativeResults;	}	public double getFalseNegatives() {		return falseNegatives;	}	/**	 * @return the falsePositiveResults	 */	public List<Result> getFalsePositiveResults() {		return falsePositiveResults;	}	public double getFalsePositives() {		return falsePositives;	}	public String getGroup() {		return group;	}	/**	 * @return the truePositiveResults	 */	public List<Result> getTruePositiveResults() {		return truePositiveResults;	}	public double getTruePositives() {		return truePositives;	}	public void incFalseNegatives() {		this.falseNegatives++;	}	public void incFalsePositives() {		this.falsePositives++;	}	public void incTruePositives() {		this.truePositives++;	}	/**	 * @return the isSeparator	 */	public boolean isSeparator() {		return isSeparator;	}	/**	 * Precision.	 * 	 * @return the float	 */	public float precision() {		if (this.falsePositives == 0 && this.truePositives == 0)			return 0f;		else			return ((float) this.truePositives / ((float) (this.truePositives + this.falsePositives)));	}	/**	 * Recall.	 * 	 * @return the float	 */	public float recall() {		if (this.falseNegatives == 0 && this.truePositives == 0)			return 0f;		else			return ((float) this.truePositives / ((float) (this.truePositives + this.falseNegatives)));	}	public void remove(final Score score) {		this.truePositives -= score.truePositives;		this.falsePositives -= score.falsePositives;		this.falseNegatives -= score.falseNegatives;		this.truePositiveResults.removeAll(score.getTruePositiveResults());		this.falsePositiveResults.removeAll(score.getFalsePositiveResults());		this.falseNegativeResults.removeAll(score.getFalseNegativeResults());	}	/**	 * @param falseNegativeResults	 *            the falseNegativeResults to set	 */	public void setFalseNegativeResults(final List<Result> falseNegativeResults) {		this.falseNegativeResults = falseNegativeResults;	}	public void setFalseNegatives(final double falseNegatives) {		this.falseNegatives = falseNegatives;	}	/**	 * @param falsePositiveResults	 *            the falsePositiveResults to set	 */	public void setFalsePositiveResults(final List<Result> falsePositiveResults) {		this.falsePositiveResults = falsePositiveResults;	}	public void setFalsePositives(final double falsePositives) {		this.falsePositives = falsePositives;	}	public void setGroup(final String group) {		this.group = group;	}	/**	 * @param isSeparator	 *            the isSeparator to set	 */	public void setSeparator(final boolean isSeparator) {		this.isSeparator = isSeparator;	}	/**	 * @param truePositiveResults	 *            the truePositiveResults to set	 */	public void setTruePositiveResults(final List<Result> truePositiveResults) {		this.truePositiveResults = truePositiveResults;	}	public void setTruePositives(final double truePositives) {		this.truePositives = truePositives;	}	@Override	public String toString() {		return "score[type:" + this.group + ", tp:" + this.truePositives				+ ", fp:" + this.falsePositives + ", fn:" + this.falseNegatives				+ "]";	}	public String toXml(final String tag) {		return "<" + tag + " type=\"" + this.group + "\" tp=\""				+ this.truePositives + "\" fp=\"" + this.falsePositives				+ "\" fn=\"" + this.falseNegatives + "\" p=\""				+ this.precision() + "\" r=\"" + this.recall() + "\" f1=\""				+ this.f1() + "\" />";	}}